mapper.select:
SELECT o.id, o.order_no, o.user_id, o.total_amount, o.pay_amount, o.freight_amount, o.status, o.receiver_name, o.receiver_phone, o.receiver_address, o.remark, o.pay_time, o.deliver_time, o.receive_time, o.cancel_time, o.cancel_reason, o.logistics_no, o.logistics_company, o.delivered, o.auto_receive_time, o.create_time FROM `order` o WHERE o.user_id = #{userId} AND o.is_deleted = 0
AND o.status = #{status}
ORDER BY o.create_time DESC

SELECT DISTINCT o.id, o.order_no, o.user_id AS buyer_id, u.nickname AS buyer_nickname, u.phone AS buyer_phone, o.total_amount, o.pay_amount, o.status, o.receiver_name, o.receiver_phone, o.receiver_address, o.remark, o.pay_time, o.deliver_time, o.logistics_no, o.logistics_company, o.create_time, (SELECT COUNT(*) FROM order_item WHERE order_id = o.id AND is_deleted = 0) AS item_count, (SELECT SUM(quantity) FROM order_item WHERE order_id = o.id AND is_deleted = 0) AS total_quantity FROM `order` o INNER JOIN order_item oi ON o.id = oi.order_id AND oi.is_deleted = 0 INNER JOIN product p ON oi.product_id = p.id AND p.is_deleted = 0 LEFT JOIN user u ON o.user_id = u.id AND u.is_deleted = 0 WHERE p.seller_id = #{sellerId} AND o.is_deleted = 0
AND o.status = #{status}
AND o.order_no LIKE CONCAT('%', #{orderNo}, '%')
AND DATE(o.create_time) >= #{startDate}
AND DATE(o.create_time) <= #{endDate}
AND (u.nickname LIKE CONCAT('%', #{keyword}, '%') OR u.phone LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY o.create_time DESC

SELECT o.status AS status, COUNT(DISTINCT o.id) AS cnt FROM `order` o INNER JOIN order_item oi ON o.id = oi.order_id AND oi.is_deleted = 0 INNER JOIN product p ON oi.product_id = p.id AND p.is_deleted = 0 WHERE p.seller_id = #{sellerId} AND o.is_deleted = 0
AND o.create_time >= #{startTime}
AND o.create_time < #{endTime}
GROUP BY o.status

SELECT oi.sku_id AS skuId, MAX(oi.sku_name) AS skuName, MAX(oi.product_name) AS productName, SUM(oi.quantity) AS salesVolume, SUM(oi.total_price) AS salesAmount FROM `order` o INNER JOIN order_item oi ON o.id = oi.order_id AND oi.is_deleted = 0 INNER JOIN product p ON oi.product_id = p.id AND p.is_deleted = 0 WHERE p.seller_id = #{sellerId} AND o.is_deleted = 0 AND o.status IN (1,2,3)
AND o.create_time >= #{startTime}
AND o.create_time < #{endTime}
GROUP BY oi.sku_id
ORDER BY salesAmount DESC
ORDER BY salesVolume DESC
LIMIT #{limit}
